 16→const TEST_DB_PATH = "./test-prompt-templates.sqlite";
 17→
 18→describe("Prompt Templates DB", () => {
 19→  beforeAll(async () => {
 20→    for (const suffix of ["", "-wal", "-shm"]) {
 21→      try {
 22→        await unlink(TEST_DB_PATH + suffix);
 23→      } catch {
 24→        // File doesn't exist
 25→      }
 26→    }
 27→    initDb(TEST_DB_PATH);
 28→  });
 29→
 30→  afterAll(async () => {
 31→    closeDb();
 32→    for (const suffix of ["", "-wal", "-shm"]) {
 33→      try {
 34→        await unlink(TEST_DB_PATH + suffix);
 35→      } catch {
 36→        // File doesn't exist
 37→      }
