 45→  describe("CRUD operations", () => {
 46→    test("create via upsert (insert path) and read by ID", () => {
 47→      const template = upsertPromptTemplate({
 48→        eventType: "github.push",
 49→        scope: "global",
 50→        body: "Handle push event: {{payload}}",
 51→        createdBy: "test-user",
 52→      });
 53→
 54→      expect(template.id).toBeTruthy();
 55→      expect(template.eventType).toBe("github.push");
 56→      expect(template.scope).toBe("global");
 57→      expect(template.scopeId).toBeNull();
 58→      expect(template.state).toBe("enabled");
 59→      expect(template.body).toBe("Handle push event: {{payload}}");
 60→      expect(template.isDefault).toBe(false);
 61→      expect(template.version).toBe(1);
 62→      expect(template.createdBy).toBe("test-user");
 63→      expect(template.createdAt).toBeTruthy();
 64→      expect(template.updatedAt).toBeTruthy();
 65→
 66→      const fetched = getPromptTemplateById(template.id);
 67→      expect(fetched).not.toBeNull();
 68→      expect(fetched!.id).toBe(template.id);
 69→      expect(fetched!.body).toBe("Handle push event: {{payload}}");
 70→    });
 71→
 72→    test("list with filters", () => {
 73→      // Create a few more templates
 74→      upsertPromptTemplate({
 75→        eventType: "github.pull_request.opened",
 76→        scope: "global",
 77→        body: "PR opened template",
 78→      });
 79→      upsertPromptTemplate({
 80→        eventType: "github.pull_request.opened",
 81→        scope: "agent",
 82→        scopeId: "agent-001",
 83→        body: "Agent-specific PR opened",
 84→      });
 85→
 86→      const allGlobal = getPromptTemplates({ scope: "global" });
 87→      expect(allGlobal.length).toBeGreaterThanOrEqual(2);
 88→
 89→      const prTemplates = getPromptTemplates({ eventType: "github.pull_request.opened" });
 90→      expect(prTemplates.length).toBe(2);
 91→
 92→      const agentTemplates = getPromptTemplates({ scope: "agent", scopeId: "agent-001" });
 93→      expect(agentTemplates.length).toBe(1);
 94→      expect(agentTemplates[0].body).toBe("Agent-specific PR opened");
 95→    });
 96→
 97→    test("update via upsert bumps version", () => {
 98→      const original = upsertPromptTemplate({
 99→        eventType: "slack.message",
100→        scope: "global",
101→        body: "Slack message v1",
102→      });
103→      expect(original.version).toBe(1);
104→
105→      const updated = upsertPromptTemplate({
106→        eventType: "slack.message",
107→        scope: "global",
108→        body: "Slack message v2",
109→        changeReason: "Improved template",
110→      });
111→      expect(updated.id).toBe(original.id);
112→      expect(updated.version).toBe(2);
113→      expect(updated.body).toBe("Slack message v2");
114→    });
115→
116→    test("delete removes template", () => {
117→      const template = upsertPromptTemplate({
118→        eventType: "test.delete_me",
119→        scope: "global",
120→        body: "Will be deleted",
121→      });
122→
123→      const deleted = deletePromptTemplate(template.id);
124→      expect(deleted).toBe(true);
125→
126→      const fetched = getPromptTemplateById(template.id);
127→      expect(fetched).toBeNull();
128→    });
