140→  describe("scope resolution precedence", () => {
141→    const agentId = "resolve-agent-001";
142→    const repoId = "resolve-repo-001";
143→
144→    test("agent scope beats repo and global", () => {
145→      upsertPromptTemplate({
146→        eventType: "resolve.test.precedence",
147→        scope: "global",
148→        body: "Global body",
149→      });
150→      upsertPromptTemplate({
151→        eventType: "resolve.test.precedence",
152→        scope: "repo",
153→        scopeId: repoId,
154→        body: "Repo body",
155→      });
156→      upsertPromptTemplate({
157→        eventType: "resolve.test.precedence",
158→        scope: "agent",
159→        scopeId: agentId,
160→        body: "Agent body",
161→      });
162→
163→      const result = resolvePromptTemplate("resolve.test.precedence", agentId, repoId);
164→      expect(result).not.toBeNull();
165→      expect("template" in result!).toBe(true);
166→      if ("template" in result!) {
167→        expect(result.template.body).toBe("Agent body");
168→        expect(result.template.scope).toBe("agent");
169→      }
170→    });
171→
172→    test("repo scope beats global when no agent template", () => {
173→      upsertPromptTemplate({
174→        eventType: "resolve.test.repo_global",
175→        scope: "global",
176→        body: "Global body",
177→      });
178→      upsertPromptTemplate({
179→        eventType: "resolve.test.repo_global",
180→        scope: "repo",
181→        scopeId: repoId,
182→        body: "Repo body",
183→      });
184→
185→      const result = resolvePromptTemplate("resolve.test.repo_global", "other-agent", repoId);
186→      expect(result).not.toBeNull();
187→      if ("template" in result!) {
188→        expect(result.template.body).toBe("Repo body");
189→      }
190→    });
191→
192→    test("falls back to global when no agent/repo template", () => {
193→      upsertPromptTemplate({
194→        eventType: "resolve.test.global_only",
195→        scope: "global",
196→        body: "Global only body",
197→      });
198→
199→      const result = resolvePromptTemplate("resolve.test.global_only", "some-agent", "some-repo");
200→      expect(result).not.toBeNull();
201→      if ("template" in result!) {
202→        expect(result.template.body).toBe("Global only body");
203→      }
204→    });
205→
206→    test("returns null when no template matches", () => {
207→      const result = resolvePromptTemplate("no.such.event", "agent-x", "repo-x");
208→      expect(result).toBeNull();
209→    });
210→  });
