 13→const TEST_DB_PATH = "./test-prompt-resolver.sqlite";
 14→
 15→describe("Prompt Template Resolver", () => {
 16→  beforeAll(async () => {
 17→    for (const suffix of ["", "-wal", "-shm"]) {
 18→      try {
 19→        await unlink(TEST_DB_PATH + suffix);
 20→      } catch {
 21→        // File doesn't exist
 22→      }
 23→    }
 24→    // Clear any previously registered templates before init
 25→    clearTemplateDefinitions();
 26→    initDb(TEST_DB_PATH);
 27→  });
 28→
 29→  afterAll(async () => {
 30→    closeDb();
 31→    clearTemplateDefinitions();
 32→    for (const suffix of ["", "-wal", "-shm"]) {
 33→      try {
 34→        await unlink(TEST_DB_PATH + suffix);
 35→      } catch {
 36→        // File doesn't exist
 37→      }
 38→    }
