 21→const TEST_DB_PATH = "./test-prompt-remaining.sqlite";
 22→
 23→/**
 24→ * Re-register all templates by dynamically re-evaluating template modules.
 25→ * Needed because other test files may call clearTemplateDefinitions() in parallel.
 26→ */
 27→async function ensureTemplatesRegistered(): Promise<void> {
 28→  // Check if templates are still registered (another test may have cleared them)
 29→  if (getTemplateDefinition("gitlab.merge_request.opened")) return;
 30→
 31→  // Force re-evaluation by importing with cache-busting query param
 32→  const ts = Date.now();
 33→  await import(`../gitlab/templates?t=${ts}`);
 34→  await import(`../agentmail/templates?t=${ts}`);
 35→  await import(`../linear/templates?t=${ts}`);
 36→  await import(`../heartbeat/templates?t=${ts}`);
 37→  await import(`../tools/templates?t=${ts}`);
 38→  await import(`../commands/templates?t=${ts}`);
 39→  await import(`../slack/templates?t=${ts}`);
 40→  await import(`../prompts/session-templates?t=${ts}`);
 41→}
 42→
 43→beforeAll(async () => {
 44→  for (const suffix of ["", "-wal", "-shm"]) {
 45→    try {
 46→      await unlink(TEST_DB_PATH + suffix);
 47→    } catch {
 48→      // File doesn't exist
 49→    }
 50→  }
 51→  initDb(TEST_DB_PATH);
 52→});
 53→
 54→beforeEach(async () => {
 55→  await ensureTemplatesRegistered();
 56→});
 57→
 58→afterAll(async () => {
 59→  closeDb();
 60→  for (const suffix of ["", "-wal", "-shm"]) {
 61→    try {
 62→      await unlink(TEST_DB_PATH + suffix);
 63→    } catch {
 64→      // File doesn't exist
 65→    }
 66→  }
