  1→import type { IncomingMessage, ServerResponse } from "node:http";
  2→import type { AgentMailWebhookPayload } from "../agentmail";
  3→import {
  4→  handleMessageReceived,
  5→  isAgentMailEnabled,
  6→  isInboxAllowed,
  7→  isSenderAllowed,
  8→  verifyAgentMailWebhook,
  9→} from "../agentmail";
 10→import type {
 11→  CheckRunEvent,
 12→  CheckSuiteEvent,
 13→  CommentEvent,
 14→  IssueEvent,
 15→  PullRequestEvent,
 16→  PullRequestReviewEvent,
 17→  WorkflowRunEvent,
 18→} from "../github";
 19→import {
 20→  handleCheckRun,
 21→  handleCheckSuite,
 22→  handleComment,
 23→  handleIssue,
 24→  handlePullRequest,
 25→  handlePullRequestReview,
 26→  handleWorkflowRun,
 27→  isGitHubEnabled,
 28→  verifyWebhookSignature,
 29→} from "../github";
 30→import type {
 31→  IssueEvent as GitLabIssueEvent,
 32→  MergeRequestEvent,
 33→  NoteEvent,
 34→  PipelineEvent,
 35→} from "../gitlab";
 36→import {
 37→  handleIssue as handleGitLabIssue,
 38→  handleMergeRequest,
 39→  handleNote,
 40→  handlePipeline,
 41→  isGitLabEnabled,
 42→  verifyGitLabWebhook,
 43→} from "../gitlab";
 44→import { workflowEventBus } from "../workflows/event-bus";
 45→import { route } from "./route-def";
 46→
 47→// ─── Route Definitions (documentation only — webhooks handle their own body parsing) ─
 48→
 49→const githubWebhook = route({
 50→  method: "post",
 51→  path: "/api/github/webhook",
 52→  pattern: ["api", "github", "webhook"],
 53→  summary: "Handle GitHub webhook events",
 54→  tags: ["Webhooks"],
 55→  auth: { apiKey: false },
 56→  responses: {
 57→    200: { description: "Event processed" },
 58→    401: { description: "Invalid signature" },
 59→    503: { description: "GitHub integration not configured" },
 60→  },
 61→});
 62→
 63→const gitlabWebhook = route({
 64→  method: "post",
 65→  path: "/api/gitlab/webhook",
 66→  pattern: ["api", "gitlab", "webhook"],
 67→  summary: "Handle GitLab webhook events",
 68→  tags: ["Webhooks"],
 69→  auth: { apiKey: false },
 70→  responses: {
 71→    200: { description: "Event processed" },
 72→    401: { description: "Invalid token" },
 73→    503: { description: "GitLab integration not configured" },
 74→  },
 75→});
 76→
 77→const agentmailWebhook = route({
 78→  method: "post",
 79→  path: "/api/agentmail/webhook",
 80→  pattern: ["api", "agentmail", "webhook"],
 81→  summary: "Handle AgentMail webhook events",
 82→  tags: ["Webhooks"],
 83→  auth: { apiKey: false },
 84→  responses: {
 85→    200: { description: "Event received" },
 86→    401: { description: "Invalid signature" },
 87→    503: { description: "AgentMail integration not configured" },
 88→  },
 89→});
 90→
 91→// ─── Handler ─────────────────────────────────────────────────────────────────
 92→
 93→export async function handleWebhooks(
 94→  req: IncomingMessage,
 95→  res: ServerResponse,
 96→  pathSegments: string[],
 97→): Promise<boolean> {
 98→  // GitHub webhook — needs raw body for signature verification
 99→  if (githubWebhook.match(req.method, pathSegments)) {
100→    if (!isGitHubEnabled()) {
101→      res.writeHead(503, { "Content-Type": "application/json" });
102→      res.end(JSON.stringify({ error: "GitHub integration not configured" }));
103→      return true;
104→    }
105→
106→    const eventType = req.headers["x-github-event"] as string | undefined;
107→    const signature = req.headers["x-hub-signature-256"] as string | undefined;
108→
109→    const chunks: Buffer[] = [];
110→    for await (const chunk of req) {
111→      chunks.push(chunk);
112→    }
113→    const rawBody = Buffer.concat(chunks).toString();
114→
115→    const isValid = await verifyWebhookSignature(rawBody, signature ?? null);
116→    if (!isValid) {
117→      console.log("[GitHub] Invalid webhook signature");
118→      res.writeHead(401, { "Content-Type": "application/json" });
119→      res.end(JSON.stringify({ error: "Invalid signature" }));
120→      return true;
121→    }
122→
123→    if (eventType === "ping") {
124→      console.log("[GitHub] Received ping event - webhook configured successfully");
125→      res.writeHead(200, { "Content-Type": "application/json" });
126→      res.end(JSON.stringify({ message: "pong" }));
127→      return true;
128→    }
129→
130→    let body: unknown;
131→    try {
132→      body = JSON.parse(rawBody);
133→    } catch {
134→      res.writeHead(400, { "Content-Type": "application/json" });
135→      res.end(JSON.stringify({ error: "Invalid JSON body" }));
136→      return true;
137→    }
138→
139→    console.log(`[GitHub] Received ${eventType} event`);
140→
141→    let result: { created: boolean; taskId?: string } = { created: false };
142→
143→    try {
144→      switch (eventType) {
145→        case "pull_request":
146→          result = await handlePullRequest(body as PullRequestEvent);
147→          break;
148→        case "issues":
149→          result = await handleIssue(body as IssueEvent);
150→          break;
151→        case "issue_comment":
152→          result = await handleComment(body as CommentEvent, "issue_comment");
153→          break;
154→        case "pull_request_review_comment":
155→          result = await handleComment(body as CommentEvent, "pull_request_review_comment");
156→          break;
157→        case "pull_request_review":
158→          result = await handlePullRequestReview(body as PullRequestReviewEvent);
159→          break;
160→        case "check_run":
161→          result = await handleCheckRun(body as CheckRunEvent);
162→          break;
163→        case "check_suite":
164→          result = await handleCheckSuite(body as CheckSuiteEvent);
165→          break;
166→        case "workflow_run":
167→          result = await handleWorkflowRun(body as WorkflowRunEvent);
168→          break;
169→        default:
170→          console.log(`[GitHub] Ignoring unsupported event type: ${eventType}`);
171→      }
172→
173→      // Emit workflow trigger event for matching event types
174→      switch (eventType) {
175→        case "pull_request": {
176→          const pr = body as unknown as PullRequestEvent;
177→          workflowEventBus.emit(`github.pull_request.${pr.action}`, {
178→            repo: pr.repository.full_name,
179→            number: pr.pull_request.number,
180→            title: pr.pull_request.title,
181→            body: pr.pull_request.body,
182→            action: pr.action,
183→            merged: pr.pull_request.merged ?? false,
184→            html_url: pr.pull_request.html_url,
185→            user_login: pr.pull_request.user.login,
186→            changed_files: pr.pull_request.changed_files,
187→          });
188→          break;
189→        }
190→        case "issues": {
191→          const iss = body as unknown as IssueEvent;
192→          workflowEventBus.emit(`github.issue.${iss.action}`, {
193→            repo: iss.repository.full_name,
194→            number: iss.issue.number,
195→            title: iss.issue.title,
196→            action: iss.action,
197→          });
198→          break;
199→        }
200→        case "issue_comment": {
201→          const ic = body as unknown as CommentEvent;
202→          workflowEventBus.emit("github.issue_comment.created", {
203→            repo: ic.repository.full_name,
204→            number: ic.issue?.number,
205→            action: ic.action,
206→          });
207→          break;
208→        }
209→        case "pull_request_review": {
210→          const prr = body as unknown as PullRequestReviewEvent;
211→          workflowEventBus.emit("github.pull_request_review.submitted", {
212→            repo: prr.repository.full_name,
213→            number: prr.pull_request.number,
214→            state: prr.review.state,
215→            action: prr.action,
216→          });
217→          break;
218→        }
219→      }
220→
221→      res.writeHead(200, { "Content-Type": "application/json" });
222→      res.end(JSON.stringify(result));
223→    } catch (err) {
224→      const errorMessage = err instanceof Error ? err.message : String(err);
225→      console.error(`[GitHub] Error handling ${eventType} event: ${errorMessage}`);
226→      if (err instanceof Error && err.stack) {
227→        console.error(err.stack);
228→      }
229→      res.writeHead(500, { "Content-Type": "application/json" });
230→      res.end(JSON.stringify({ error: "Internal server error", message: errorMessage }));
231→    }
232→    return true;
233→  }
234→
235→  // GitLab webhook — needs raw body + custom token verification
236→  if (gitlabWebhook.match(req.method, pathSegments)) {
237→    if (!isGitLabEnabled()) {
238→      res.writeHead(503, { "Content-Type": "application/json" });
239→      res.end(JSON.stringify({ error: "GitLab integration not configured" }));
240→      return true;
241→    }
242→
243→    const token = req.headers["x-gitlab-token"] as string | undefined;
244→    if (!verifyGitLabWebhook(token)) {
245→      console.log("[GitLab] Invalid webhook token");
246→      res.writeHead(401, { "Content-Type": "application/json" });
247→      res.end(JSON.stringify({ error: "Invalid token" }));
248→      return true;
249→    }
250→
251→    const chunks: Buffer[] = [];
252→    for await (const chunk of req) {
253→      chunks.push(chunk);
254→    }
255→    const rawBody = Buffer.concat(chunks).toString();
256→
257→    let body: Record<string, unknown>;
258→    try {
259→      body = JSON.parse(rawBody);
260→    } catch {
261→      res.writeHead(400, { "Content-Type": "application/json" });
262→      res.end(JSON.stringify({ error: "Invalid JSON body" }));
263→      return true;
264→    }
265→
266→    const objectKind = body.object_kind as string | undefined;
267→    console.log(`[GitLab] Received ${objectKind} event`);
268→
269→    let result: { created: boolean; taskId?: string } = { created: false };
270→
271→    try {
272→      switch (objectKind) {
273→        case "merge_request":
274→          result = await handleMergeRequest(body as unknown as MergeRequestEvent);
275→          break;
276→        case "issue":
277→          result = await handleGitLabIssue(body as unknown as GitLabIssueEvent);
278→          break;
279→        case "note":
280→          result = await handleNote(body as unknown as NoteEvent);
281→          break;
282→        case "pipeline":
283→          result = await handlePipeline(body as unknown as PipelineEvent);
284→          break;
285→        default:
286→          console.log(`[GitLab] Ignoring unsupported event type: ${objectKind}`);
287→      }
288→
289→      // Emit workflow trigger events for GitLab
290→      switch (objectKind) {
291→        case "merge_request": {
292→          const mr = body as unknown as MergeRequestEvent;
293→          const action = mr.object_attributes.action;
294→          workflowEventBus.emit(`gitlab.merge_request.${action}`, {
295→            repo: mr.project.path_with_namespace,
296→            number: mr.object_attributes.iid,
297→            title: mr.object_attributes.title,
298→            body: mr.object_attributes.description,
299→            action,
300→            merged: mr.object_attributes.state === "merged",
301→            html_url: mr.object_attributes.url,
302→            user_login: mr.user.username,
303→          });
304→          break;
305→        }
306→        case "issue": {
307→          const iss = body as unknown as GitLabIssueEvent;
308→          workflowEventBus.emit(`gitlab.issue.${iss.object_attributes.action}`, {
309→            repo: iss.project.path_with_namespace,
310→            number: iss.object_attributes.iid,
311→            title: iss.object_attributes.title,
312→            action: iss.object_attributes.action,
313→          });
314→          break;
315→        }
316→        case "note": {
317→          const note = body as unknown as NoteEvent;
318→          workflowEventBus.emit("gitlab.note.created", {
319→            repo: note.project.path_with_namespace,
320→            number: note.merge_request?.iid ?? note.issue?.iid,
321→            action: "created",
322→          });
323→          break;
324→        }
325→        case "pipeline": {
326→          const pl = body as unknown as PipelineEvent;
327→          workflowEventBus.emit(`gitlab.pipeline.${pl.object_attributes.status}`, {
328→            repo: pl.project.path_with_namespace,
329→            number: pl.merge_request?.iid,
330→            status: pl.object_attributes.status,
331→            action: pl.object_attributes.status,
332→          });
333→          break;
334→        }
335→      }
336→
337→      res.writeHead(200, { "Content-Type": "application/json" });
338→      res.end(JSON.stringify(result));
339→    } catch (err) {
340→      const errorMessage = err instanceof Error ? err.message : String(err);
341→      console.error(`[GitLab] Error handling ${objectKind} event: ${errorMessage}`);
342→      if (err instanceof Error && err.stack) {
343→        console.error(err.stack);
344→      }
345→      res.writeHead(500, { "Content-Type": "application/json" });
346→      res.end(JSON.stringify({ error: "Internal server error" }));
347→    }
348→    return true;
349→  }
350→
351→  // AgentMail webhook — needs raw body for Svix signature verification
352→  if (agentmailWebhook.match(req.method, pathSegments)) {
353→    if (!isAgentMailEnabled()) {
354→      res.writeHead(503, { "Content-Type": "application/json" });
355→      res.end(JSON.stringify({ error: "AgentMail integration not configured" }));
356→      return true;
357→    }
358→
359→    const chunks: Buffer[] = [];
360→    for await (const chunk of req) {
361→      chunks.push(chunk);
362→    }
363→    const rawBody = Buffer.concat(chunks).toString();
364→
365→    const svixHeaders: Record<string, string> = {};
366→    for (const key of ["svix-id", "svix-timestamp", "svix-signature"]) {
367→      const value = req.headers[key];
368→      if (typeof value === "string") {
369→        svixHeaders[key] = value;
370→      }
371→    }
372→
373→    const verified = verifyAgentMailWebhook(rawBody, svixHeaders);
374→    if (!verified) {
375→      console.log("[AgentMail] Invalid webhook signature");
376→      res.writeHead(401, { "Content-Type": "application/json" });
377→      res.end(JSON.stringify({ error: "Invalid signature" }));
378→      return true;
379→    }
380→
381→    // Return 200 immediately — Svix best practice to avoid retries.
382→    // Processing happens asynchronously below; dedup is handled in handlers.ts.
383→    res.writeHead(200, { "Content-Type": "application/json" });
384→    res.end(JSON.stringify({ received: true }));
385→
386→    const payload = verified as AgentMailWebhookPayload;
387→
388→    if (
389→      payload.message &&
390→      !isInboxAllowed(payload.message.inbox_id, process.env.AGENTMAIL_INBOX_DOMAIN_FILTER)
391→    ) {
392→      const domain = payload.message.inbox_id.split("@")[1] ?? "unknown";
393→      console.log(
394→        `[AgentMail] Ignoring event for inbox domain "${domain}" (not in AGENTMAIL_INBOX_DOMAIN_FILTER)`,
395→      );
396→      return true;
397→    }
398→
399→    if (
400→      payload.message &&
401→      !isSenderAllowed(payload.message.from_, process.env.AGENTMAIL_SENDER_DOMAIN_FILTER)
402→    ) {
403→      const from = Array.isArray(payload.message.from_)
404→        ? payload.message.from_.join(", ")
405→        : payload.message.from_;
406→      console.log(
407→        `[AgentMail] Ignoring event from sender "${from}" (not in AGENTMAIL_SENDER_DOMAIN_FILTER)`,
408→      );
409→      return true;
410→    }
411→    console.log(`[AgentMail] Received ${payload.event_type} event (${payload.event_id})`);
412→
413→    try {
414→      switch (payload.event_type) {
415→        case "message.received":
416→          await handleMessageReceived(payload);
417→          break;
418→        default:
419→          console.log(`[AgentMail] Ignoring event type: ${payload.event_type}`);
420→      }
421→    } catch (err) {
422→      const errorMessage = err instanceof Error ? err.message : String(err);
423→      console.error(`[AgentMail] Error handling ${payload.event_type} event: ${errorMessage}`);
424→      if (err instanceof Error && err.stack) {
425→        console.error(err.stack);
426→      }
427→    }
428→    return true;
429→  }
430→
431→  return false;
432→}
