 37→
 38→const port = parseInt(process.env.PORT || process.argv[2] || "3013", 10);
 39→const apiKey = process.env.API_KEY || "";
 40→
 41→// Use globalThis to persist state across hot reloads
 42→const globalState = globalThis as typeof globalThis & {
 43→  __httpServer?: Server<typeof IncomingMessage, typeof ServerResponse>;
 44→  __transports?: Record<string, StreamableHTTPServerTransport>;
 45→  __sigintRegistered?: boolean;
 46→};
 47→
 48→// Clean up previous server on hot reload
 49→if (globalState.__httpServer) {
 50→  console.log("[HTTP] Hot reload detected, closing previous server...");
 51→  globalState.__httpServer.close();
 52→}
 53→
 54→const transports: Record<string, StreamableHTTPServerTransport> = globalState.__transports ?? {};
 55→
 56→const httpServer = createHttpServer(async (req, res) => {
 57→  const startTime = performance.now();
 58→  let statusCode = 200;
 59→
 60→  // Wrap writeHead to capture status code
 61→  const originalWriteHead = res.writeHead.bind(res);
 62→  res.writeHead = (code: number, ...args: unknown[]) => {
 63→    statusCode = code;
 64→    // @ts-expect-error - writeHead has multiple overloads
 65→    return originalWriteHead(code, ...args);
 66→  };
 67→
 68→  // Log request completion
 69→  const logRequest = () => {
 70→    const elapsed = (performance.now() - startTime).toFixed(1);
 71→    const statusEmoji = statusCode >= 400 ? "⚠️" : "✓";
 72→    console.log(`[HTTP] ${statusEmoji} ${req.method} ${req.url} → ${statusCode} (${elapsed}ms)`);
 73→  };
 74→
 75→  // Ensure we log on response finish
 76→  res.on("finish", logRequest);
 77→
 78→  // Log errors
 79→  res.on("error", (err) => {
 80→    console.error(`[HTTP] ❌ ${req.method} ${req.url} → Error: ${err.message}`);
 81→  });
 82→
 83→  setCorsHeaders(res);
 84→
 85→  // ── Core routes (OPTIONS, health, auth, /me, /cancelled-tasks, /ping, /close) ──
 86→  if (await handleCore(req, res, req.headers["x-agent-id"] as string | undefined, apiKey)) return;
