103→    () => handleActiveSessions(req, res, pathSegments, queryParams, myAgentId),
104→    () => handleEpics(req, res, pathSegments, queryParams, myAgentId),
105→    () => handleSchedules(req, res, pathSegments, queryParams, myAgentId),
