 23→ */
 24→export function getReviewStateInfo(state: string): { emoji: string; label: string } {
 25→  switch (state) {
 26→    case "approved":
 27→      return { emoji: "✅", label: "APPROVED" };
 28→    case "changes_requested":
 29→      return { emoji: "🔄", label: "CHANGES REQUESTED" };
 30→    case "commented":
 31→      return { emoji: "💬", label: "COMMENTED" };
 32→    case "dismissed":
 33→      return { emoji: "🚫", label: "DISMISSED" };
