 43→  emoji: string;
 44→  label: string;
 45→} {
 46→  switch (conclusion) {
 47→    case "success":
 48→      return { emoji: "✅", label: "PASSED" };
 49→    case "failure":
 50→      return { emoji: "❌", label: "FAILED" };
 51→    case "cancelled":
 52→      return { emoji: "⏹️", label: "CANCELLED" };
