 84→function isDuplicate(eventKey: string): boolean {
 85→  const now = Date.now();
 86→
 87→  // Clean old entries
 88→  for (const [key, timestamp] of processedEvents) {
 89→    if (now - timestamp > EVENT_TTL) {
 90→      processedEvents.delete(key);
 91→    }
 92→  }
 93→
 94→  if (processedEvents.has(eventKey)) {
 95→    return true;
 96→  }
 97→
 98→  processedEvents.set(eventKey, now);
 99→  return false;
100→}
