102→/**
103→ * Find the lead agent to receive GitHub tasks
104→ * Returns null if no lead is available (task will go to pool)
105→ */
106→function findLeadAgent() {
107→  const agents = getAllAgents();
108→  // First try to find an online lead
109→  const onlineLead = agents.find((a) => a.isLead && a.status !== "offline");
110→  if (onlineLead) return onlineLead;
111→  // Fall back to any lead (even offline) - task will be waiting for them
112→  return agents.find((a) => a.isLead) ?? null;
