const BASE = "http://localhost:3098";
const AUTH = "Bearer 123123";
const SECRET = "e2e-test-secret";

async function sign(payload: string): Promise<string> {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw", encoder.encode(SECRET), { name: "HMAC", hash: "SHA-256" }, false, ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(payload));
  const hex = Array.from(new Uint8Array(sig)).map(b => b.toString(16).padStart(2, "0")).join("");
  return `sha256=${hex}`;
}

async function sendWebhook(event: string, payload: object) {
  const body = JSON.stringify(payload);
  const signature = await sign(body);
  const resp = await fetch(`${BASE}/api/github/webhook`, {
    method: "POST",
    headers: {
      "Authorization": AUTH, "Content-Type": "application/json",
      "X-GitHub-Event": event, "X-Hub-Signature-256": signature,
    },
    body,
  });
  const text = await resp.text();
  let result: any;
  try { result = JSON.parse(text); } catch { result = text; }
  return { status: resp.status, result };
}

